const fs = require('fs');
const path = require('path');
const files = [
  '/tmp/pi-live-drive-64ZPrf/run1-single.stdout.jsonl',
  '/tmp/pi-live-drive-64ZPrf/run2-mem-store.stdout.jsonl',
  '/tmp/pi-live-drive-64ZPrf/run3-mem-recall.stdout.jsonl',
];
for (const file of files) {
  const lines = fs.readFileSync(file,'utf8').trim().split(/\n+/).filter(Boolean);
  const objs = lines.map(l=>{ try { return JSON.parse(l); } catch(e) { return null; } }).filter(Boolean);
  const agentEnd = objs.findLast?.(o=>o.type==='agent_end') || [...objs].reverse().find(o=>o.type==='agent_end');
  const toolExecEnd = objs.filter(o=>o.type==='tool_execution_end');
  const lastMsgEnd = [...objs].reverse().find(o=>o.type==='message_end' && o.message?.role==='assistant');
  const assistantFinalText = lastMsgEnd?.message?.content?.filter?.(p=>p.type==='text').map(p=>p.text).join('\n') || '';
  let hasDispatchCall = false;
  let dispatchArgs = [];
  if (agentEnd?.messages) {
    for (const m of agentEnd.messages) {
      if (m.role === 'assistant') {
        for (const p of m.content || []) {
          if (p.type === 'toolCall' && p.name === 'dispatch') {
            hasDispatchCall = true;
            dispatchArgs.push(p.arguments);
          }
        }
      }
    }
  }
  const dispatchResults = agentEnd?.messages?.filter?.(m=>m.role==='toolResult' && m.toolName==='dispatch') || [];
  const dispatchTexts = dispatchResults.flatMap(m => (m.content||[]).filter(p=>p.type==='text').map(p=>p.text));
  const workerAssistants = dispatchResults.flatMap(m => (((m.details||{}).items||[]))).flatMap(item => ((item.result?.messages||[]).filter(mm=>mm.role==='assistant')));
  const workerAssistantTexts = workerAssistants.flatMap(m => (m.content||[]).filter(p=>p.type==='text').map(p=>p.text));
  console.log(`FILE ${path.basename(file)}`);
  console.log(`  dispatchToolCall=${hasDispatchCall}`);
  console.log(`  dispatchArgs=${JSON.stringify(dispatchArgs)}`);
  console.log(`  dispatchTexts=${JSON.stringify(dispatchTexts)}`);
  console.log(`  workerAssistantTexts=${JSON.stringify(workerAssistantTexts)}`);
  console.log(`  finalAssistantText=${JSON.stringify(assistantFinalText)}`);
  console.log(`  toolExecutionEndCount=${toolExecEnd.length}`);
  console.log('');
}
