    outerSession: `${ART}/outer-run1.jsonl`,
    workerSession: '/home/bitzaven/CodingProjects/pi-threads/.pi/threads/bugsearch-single.jsonl',
    exitCode: 0,
  },
  {
    name: 'run2-mem-store',
    expected: 'BANANA-441',
    stdout: `${ART}/run2-mem-store.stdout.jsonl`,
    stderr: `${ART}/run2-mem-store.stderr.txt`,
    outerSession: `${ART}/outer-run2.jsonl`,
    workerSession: '/home/bitzaven/CodingProjects/pi-threads/.pi/threads/bugsearch-mem.jsonl',
    exitCode: 0,
  },
  {
    name: 'run3-mem-recall',
    expected: 'BANANA-441',
    stdout: `${ART}/run3-mem-recall.stdout.jsonl`,
    stderr: `${ART}/run3-mem-recall.stderr.txt`,
    outerSession: `${ART}/outer-run3.jsonl`,
    workerSession: '/home/bitzaven/CodingProjects/pi-threads/.pi/threads/bugsearch-mem.jsonl',
    exitCode: 0,
  }
];
function parseJsonl(file) {
  return fs.readFileSync(file, 'utf8').trim().split(/\n+/).filter(Boolean).map(line => JSON.parse(line));
}
for (const run of runs) {
  const objs = parseJsonl(run.stdout);
  const agentEnd = [...objs].reverse().find(o => o.type === 'agent_end');
  const assistantMsgs = (agentEnd?.messages || []).filter(m => m.role === 'assistant');
  const toolCalls = assistantMsgs.flatMap(m => m.content || []).filter(p => p.type === 'toolCall');
  const dispatchCalls = toolCalls.filter(p => p.name === 'dispatch');
  const dispatchResults = (agentEnd?.messages || []).filter(m => m.role === 'toolResult' && m.toolName === 'dispatch');
  const dispatchTexts = dispatchResults.flatMap(m => (m.content || []).filter(p => p.type === 'text').map(p => p.text));
  const workerTexts = dispatchResults.flatMap(m => ((m.details?.items || []).flatMap(item => (item.result?.messages || []).filter(mm => mm.role === 'assistant')))).flatMap(m => (m.content || []).filter(p => p.type === 'text').map(p => p.text));
  const finalAssistantText = assistantMsgs.length ? assistantMsgs[assistantMsgs.length - 1].content.filter(p => p.type === 'text').map(p => p.text).join('\n') : '';
  run.dispatchToolCall = dispatchCalls.length > 0;
  run.dispatchArgs = dispatchCalls.map(c => c.arguments);
  run.dispatchTexts = dispatchTexts;
  run.workerAssistantTexts = workerTexts;
  run.finalAssistantText = finalAssistantText;
  run.expectedAppearedInDispatchResult = dispatchTexts.some(t => t.includes(run.expected));
  run.expectedAppearedInWorkerAssistant = workerTexts.some(t => t.includes(run.expected));
  run.expectedAppearedInFinalAssistant = finalAssistantText.includes(run.expected);
  run.stderrBytes = fs.existsSync(run.stderr) ? fs.statSync(run.stderr).size : null;
  run.outerSessionExists = fs.existsSync(run.outerSession);
  run.workerSessionExists = fs.existsSync(run.workerSession);
}
const summary = {
  artifactDir: ART,
  sessionFlagWorked: runs.every(r => r.outerSessionExists),
  note: 'Distinct outer session files were used per invocation to avoid outer-session memory contaminating the recall check.',
  runs,
};
fs.writeFileSync(`${ART}/summary.json`, JSON.stringify(summary, null, 2));
console.log(`${ART}/summary.json`);
